package com.sankuai.meituan.waimai.bizad.billing.constants;

import com.google.common.collect.ImmutableMap;

import java.util.Map;

/**
 * Created by xuhao16 on 2018/11/29 下午8:40.
 */
public enum MoneyADProdType
{
    List_CPC(1),
    TJ_CPM(2),
    KA_CPT(3),
    SEARCH_CPC(4),
    BJ_CPM(5),
    KA_BJ_CPM(6),
    ZS_CPM(7),
    KA_TJ_CPM(8),
    PZ_CPM(9),
    KA_SEARCH_CPC(10),
    SMS_VAS(11),
    KA_CONTRACT_CPT(12),
    PZ_CPT(13),
    KA_CPS(14),
    CPS(15),
    TAG_CPT(16),
    KGR_CPT(17),
    KA_ZZ_CPM(18),
    KA_JTLM(19),
    KA_CHOOSE4U(20),
    AD_HETERO(21),
    SUPER_STYLE(22),
    KA_SUPPER_STYLE(23),
    CHOOSE4U(24),
    KA_KGR_CPT(25),
    MERCHANT(26),
    KDB(28),
    SUPER_EXPOSE(38),
    SG_CONTRACT(39),
    // 医药店厂协同
    MEDICINE_DCXT(67),
    // 置顶卡
    TOP_CARD(68),
    SG_BRAND_EXTERNAL_DISPATCH(69),
    SG_BRAND_INTERNAL_CONTRACT_RESOURCES(70),
    SG_CONTRACT_KA(71),
    TAG_CPT_KA(73),
    BRAND_SHOW(74),
    DISH_KEYWORD(76),
    MEDICINE_JINGANG_CPT(83),
    SGBRAND_CONTRACT(84),
    SHANGOU_BRAND_ZW(86),
    //药企品牌商GD
    CPM_MED_VENDOR_SEARCHCONTRACT(87),
    //闪购品牌商GD
    CPM_SG_VENDOR_SEARCHCONTRACT(88),
    //闪购品专CPT
    CPT_SG_KA_SEARCHCONTRACT(89),
    //闪购品专GD
    CPM_SG_KA_SEARCHCONTRACT(90),
    GD_WM_KA_THEMECONTRACT(91), // 主题列表 - GD
    CPT_WM_KA_CROSS_POI_BUY(92), // 跨店购 - CPT
    // 医药站外抖音明投
    CPM_MED_WENDOR_ZW(93),
    CPM_MED_VENDOR_ZWRED(94), // 医药品牌商站外红包
    GD_WM_PZ_PLC(95) // 外卖品专品类词
    ;


    int value;
    private static final Map<Integer, MoneyADProdType> VALUE_MAP;

    static {
        final ImmutableMap.Builder<Integer, MoneyADProdType> b = ImmutableMap.builder();
        for (MoneyADProdType enumItem : values())
        {
            b.put(enumItem.value, enumItem);
        }

        VALUE_MAP = b.build();
    }

    private MoneyADProdType(int value)
    {
        this.value = value;
    }

    public int getIntValue()
    {
        return value;
    }

    public static MoneyADProdType forValue(int valueArg)
    {
        return VALUE_MAP.get(valueArg);
    }

}

